const Header = () => {
  const { user } = useContext(AppContext);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);

  // Моковые данные, если контекст пуст
  const userName = user?.name || 'DEMO ЮРИДИЧЕСКОЕ ЛИЦО';
  const avatarUrl = user?.avatar || 'data:image/png;base64,'; // можно заглушку

  return (
    <header className={styles.header}>
      {/* Левая часть: только логотип (гамбургер скрыт на десктопе) */}
      <div className={styles.left}>
        <div className={styles.logo}>
          <img src="/logo.svg" alt="СберБизнес" />
        </div>
      </div>

      {/* Правая часть */}
      <div className={styles.right}>
        {/* Иконка телефона (контакты менеджера) */}
        <button className={styles.iconButton} title="Контакты">
          <PhoneIcon />
        </button>

        {/* Иконка уведомлений */}
        <button className={styles.iconButton} title="Уведомления">
          <NotificationIcon />
        </button>

        {/* Иконка конверта (сообщения) */}
        <button className={styles.iconButton} title="Сообщения">
          <EnvelopeIcon />
        </button>

        {/* Профиль пользователя */}
        <div className={styles.profileWrapper}>
          <button
            className={styles.profileButton}
            onClick={() => setProfileMenuOpen(prev => !prev)}
          >
            <img className={styles.avatar} src={avatarUrl} alt="avatar" />
            <span className={styles.userName}>{userName}</span>
            <svg className={styles.chevron} width="12" height="12" viewBox="0 0 1024 1024">
              <path fill="#1F1F20" transform="rotate(180, 512,512)"
                d="M509.467 220.51l487.681 436.346c34.223 34.223 34.223 85.558 8.556 119.781-34.223 34.223-85.558 34.223-119.781 8.556l-376.455-342.232-367.9 333.676c-34.223 34.223-85.558 25.667-119.781-8.556s-25.667-85.558 8.556-119.781l479.125-427.79z" />
            </svg>
          </button>
          {/* Выпадающее меню профиля (заглушка) */}
          {profileMenuOpen && (
            <div className={styles.profileDropdown}>
              <div className={styles.dropdownItem}>Сменить организацию</div>
              <div className={styles.dropdownItem}>Настройки</div>
              <div className={styles.dropdownItem}>Выйти</div>
            </div>
          )}
        </div>

        {/* Кнопка помощи "?" */}
        <button className={styles.helpButton} title="Помощь">
          <HelpIcon />
        </button>
      </div>
    </header>
  );
};

export default Header;